// Loop through all items coming from the previous node
for (const item of $input.all()) {

  // 1. DATA EXTRACTION
  const body = item.json.body || $('Webhook').item.json.body;

  // Helper: Handle Airtable array lookups safely
  const safeGet = (val) => {
    if (Array.isArray(val)) return val[0] || '';
    return val || '';
  };

  // Helper: Format Date Friendly (YYYY-MM-DD -> January 30, 2026)
  const formatFriendlyDate = (dateStr) => {
    if (!dateStr) return "TBD";
    // Split string to create a local date object (avoids timezone subtract issues)
    const [year, month, day] = dateStr.split('-');
    if (!year || !month || !day) return dateStr; 

    const date = new Date(year, month - 1, day);
    return date.toLocaleDateString('en-US', { 
      month: 'long', 
      day: 'numeric', 
      year: 'numeric' 
    });
  };

  // --- VARIABLES ---
  const clientName = safeGet(body.clients);
  const vaName = safeGet(body.virtualAssistant);
  const engagementName = safeGet(body.mvaPair);

  // Handle Reason object
  const reasonObj = body.reasonForCancellation;
  const reason = (reasonObj && reasonObj.name) ? reasonObj.name : "N/A";

  // Format the date here
  const rawDate = body.mvaLastWorkingDay;
  const lastWorkingDay = formatFriendlyDate(rawDate);

  // Handle newlines in the summary for HTML rendering
  const rawSummary = body.summaryOfCancellation || "No summary provided.";
  const summaryHtml = rawSummary.replace(/\n/g, '<br>');

  // Created By logic
  const creatorObj = body.createdBy;
  const requestorName = creatorObj ? creatorObj.name : "System";
  const requestorEmail = creatorObj ? creatorObj.email : "placements@scalevirtually.com";

  // 2. SLACK MESSAGE CONSTRUCTION
  const slackMessage = `Hi Team, a Cancellation Form has been submitted.
Details:
• Client: ${clientName}
• VA: ${vaName}
• Reason: ${reason}
• Last Working Day: ${lastWorkingDay}

Please check your email for the full summary.`;

  // 3. HTML EMAIL CONSTRUCTION
  const htmlContent = `
<!DOCTYPE html>
<html>
<head>
<style>
  html, body { margin: 0; padding: 0; background-color: #f4f6f8; }
  body { font-family: Helvetica, Arial, sans-serif; color: #333333; line-height: 1.6; font-size: 14px; }
  .outer-wrapper { width: 100%; background-color: #f4f6f8; padding: 20px 0; }
  .container { max-width: 600px; margin: 0 auto; border: 1px solid #e5e7eb; border-radius: 8px; padding: 30px; background-color: #ffffff; text-align: left; }
  .header-title { color: #E8833A; font-size: 20px; font-weight: 800; text-transform: uppercase; margin-bottom: 20px; border-bottom: 2px solid #E8833A; padding-bottom: 10px; text-align: center; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
  td { padding: 10px 0; vertical-align: top; font-size: 14px; border-bottom: 1px solid #f0f0f0; }
  .label-col { width: 35%; font-weight: 700; color: #111827; padding-right: 10px; white-space: nowrap; }
  .value-col { width: 65%; color: #374151; }
  .link-text { color: #E8833A; font-weight: 600; text-decoration: none; }
  .footer { margin-top: 30px; font-size: 12px; color: #6b7280; border-top: 1px solid #e5e7eb; padding-top: 15px; }
  a { color: #2563EB; text-decoration: none; }
</style>
</head>
<body>

<table class="outer-wrapper" role="presentation" cellspacing="0" cellpadding="0">
  <tr>
    <td align="center">
      <div class="container">

        <p>Hi Team,</p>
        <p>A new <strong>Cancellation Form</strong> has been submitted by ${requestorName}.</p>
        <br>

        <div class="header-title">Cancellation Details</div>

        <table role="presentation">

          <tr>
            <td colspan="2" class="label-col" style="padding-bottom: 5px; color: #E8833A;">SUMMARY OF CANCELLATION:</td>
          </tr>
          <tr>
            <td colspan="2" class="value-col" style="background-color: #fafafa; padding: 15px; border-radius: 4px; font-style: italic; border: 1px solid #eee;">
              "${summaryHtml}"
            </td>
          </tr>
          <tr><td colspan="2" style="height: 15px;"></td></tr>

          <tr>
            <td class="label-col">Client:</td>
            <td class="value-col"><strong>${clientName}</strong></td>
          </tr>
          <tr>
            <td class="label-col">Virtual Assistant:</td>
            <td class="value-col"><strong>${vaName}</strong></td>
          </tr>
          <tr>
            <td class="label-col">Engagement:</td>
            <td class="value-col">${engagementName}</td>
          </tr>
           <tr>
            <td class="label-col">Reason:</td>
            <td class="value-col">${reason}</td>
          </tr>
          <tr>
            <td class="label-col">Last Working Day:</td>
            <td class="value-col">${lastWorkingDay}</td>
          </tr>
          <tr>
            <td class="label-col">Submitted By:</td>
            <td class="value-col"><a href="mailto:${requestorEmail}">${requestorName}</a></td>
          </tr>

        </table>

        <div class="footer">
          This is an automated email.
        </div>

      </div>
    </td>
  </tr>
</table>

</body>
</html>
  `;

  // OUTPUTS
  item.json.cancellation_email_html = htmlContent;
  item.json.slack_message_text = slackMessage;
  item.json.email_subject = `MVA Cancellation for ${clientName} - ${vaName}`;
}

return $input.all();

